query nftList($contractAddress: String = "", $offset: Int = 10, $limit: Int = 10, $searchText: String = "", $sortValue: order_by = asc) {
  nfts(where: {contract_address: {_eq: $contractAddress}, name: {_ilike: $searchText}}, order_by: {created_at: $sortValue}, limit: $limit, offset: $offset) {
    contract_address
    created_at
    id
    metadata
    name
    owner_address
    token_id
    updated_at
    listingInfo {
      auction_config
      buyer_address
      contract_address
      created_at
      deleted_at
      id
      latest_price
      seller_address
      status
    }
  }
  nfts_aggregate {
    aggregate {
      count
    }
  }
}

