query nftListings($_ilike: String, $ownerAddress: String, $_lte: numeric, $_gte: numeric, $_in: [String!], $latest_price: order_by, $created_at: order_by = desc, $limit: Int = 10, $offset: Int = 10, $store_address: String!, $collectionAddress: [String!] = "", $updated_at: order_by, $currentDate: timestamptz = "") {
      listings(where: {start_time: {_lte: $currentDate}, nft: {name: {_ilike: $_ilike}, owner_address: {_eq: $ownerAddress}, collection: {contract_address: {_in: $collectionAddress}}}, latest_price: {_lte: $_lte, _gte: $_gte}, status: {_in: $_in}, store: {contract_address: {_eq: $store_address}}}, order_by: {latest_price: $latest_price, nft: {}, created_at: $created_at, updated_at: $updated_at}, limit: $limit, offset: $offset) {
        id
        auction_config
        status
        nft {
          metadata
          contract_address
          token_id
          collection {
            contract_address
            name
          }
        }
        updated_at
        created_at
      }
      listings_aggregate(where: {start_time: {_lte: $currentDate}, nft: {name: {_ilike: $_ilike}, owner_address: {_eq: $ownerAddress}, collection: {contract_address: {_in: $collectionAddress}}}, latest_price: {_lte: $_lte, _gte: $_gte}, status: {_in: $_in}, store: {contract_address: {_eq: $store_address}}}, order_by: {latest_price: $latest_price, nft: {}, created_at: $created_at}) {
        aggregate {
          count
        }
      }
      collections(where: {nfts: {listingInfo: {store_address: {_eq: $store_address}}}}) {
        name
        contract_address
      }
    }

