query activities($ownerAddress: String = "", $regex: String = "", $offset: Int = 0, $limit: Int = 10) {
  nft_histories(where: {
    _or: [
      {from_address: {_eq: $ownerAddress}},
      {to_address: {_eq: $ownerAddress}}
    ],
    _and: {event: {_regex: $regex}}
    },
    limit: $limit,
    offset: $offset,
    order_by: {transaction_time: desc})
    {
      contract_address
      event
      from_address
      to_address
      transaction_time
      transaction_hash
      price
      token_id
      nft {
        name
        metadata
      }
    }
    nft_histories_aggregate(where: {
      _or: [
      {from_address: {_eq: $ownerAddress}},
      {to_address: {_eq: $ownerAddress}}
    ],
    _and: {event: {_regex: $regex}}}) {
      aggregate {
        count
      }
    }
  }

